const fs=require('fs'),path=require('path'),zlib=require('zlib');
const FILE=path.join(process.cwd(),'safetypro_audit_compliance.html');
if(!fs.existsSync(FILE)){console.error('Run from project folder');process.exit(1);}
const bk=FILE.replace('.html','_bk_v5b_'+Date.now()+'.html');
fs.copyFileSync(FILE,bk);console.log('Backup:',path.basename(bk));
const html=zlib.gunzipSync(Buffer.from('','base64')).toString('utf8');
fs.writeFileSync(FILE,html,'utf8');
console.log('Done!',Math.round(html.length/1024),'KB');
console.log('Deploy: npx wrangler pages deploy . --project-name safetypro-frontend');
